export default function App() {
  const [tab, setTab] = useState("count");
  const [entries, setEntries] = useState([]);
  const [expandedId, setExpandedId] = useState(null);
  const [nextId, setNextId] = useState(1);
  const [deployId, setDeployId] = useState("");
  const [showSettings, setShowSettings] = useState(false);
  const [search, setSearch] = useState("");
  const [catFilter, setCatFilter] = useState("All");
  const [showCatalogPicker, setShowCatalogPicker] = useState(null);
  const [pickerCat, setPickerCat] = useState("All");
  const [syncStatus, setSyncStatus] = useState("");
  const entriesRef = useRef(entries);
  entriesRef.current = entries;

  // Load saved state
  useEffect(() => {
    try {
      const saved = window.sessionStorage?.getItem?.("ngd_entries");
      if (saved) { const p = JSON.parse(saved); setEntries(p); setNextId(p.length > 0 ? Math.max(...p.map(e => e.id)) + 1 : 1); }
    } catch {}
    try { const u = window.sessionStorage?.getItem?.("ngd_deploy_id"); if (u) setDeployId(u); } catch {}
  }, []);

  // Save local
  useEffect(() => { try { window.sessionStorage?.setItem?.("ngd_entries", JSON.stringify(entries)); } catch {} }, [entries]);
  useEffect(() => { try { window.sessionStorage?.setItem?.("ngd_deploy_id", deployId); } catch {} }, [deployId]);

  // Pull on open + interval
  const doSync = useCallback(async () => {
    if (!deployId) return;
    setSyncStatus("syncing…");
    const remote = await pullState(deployId);
    if (remote && Array.isArray(remote)) {
      const merged = mergeEntries(entriesRef.current, remote);
      setEntries(merged);
      setNextId(merged.length > 0 ? Math.max(...merged.map(e => e.id)) + 1 : 1);
    }
    setSyncStatus("synced");
    setTimeout(() => setSyncStatus(""), 2000);
  }, [deployId]);

  useEffect(() => {
    if (!deployId) return;
    doSync();
    const interval = setInterval(doSync, SYNC_INTERVAL);
    return () => clearInterval(interval);
  }, [deployId, doSync]);

  // Push on every change
  const pushUpdate = useCallback((newEntries, changedEntry, action) => {
    pushState(deployId, newEntries);
    if (changedEntry) pushLog(deployId, changedEntry, action);
  }, [deployId]);

  const addEntry = useCallback(() => {
    const now = new Date();
    const time = now.toLocaleTimeString("en-US", { hour: "numeric", minute: "2-digit" });
    const newId = entries.length > 0 ? Math.max(...entries.map(e => e.id)) + 1 : 1;
    const entry = { id: newId, time, engage: "", amount: "", items: "", soldCatalogIds: [], payment: "", note: "", ts: now.toISOString() };
    const newEntries = [entry, ...entries];
    setEntries(newEntries);
    setExpandedId(newId);
    setNextId(newId + 1);
    pushUpdate(newEntries, entry, "add");
  }, [entries, pushUpdate]);

  const undoEntry = useCallback(() => {
    if (entries.length === 0) return;
    const removed = entries[0];
    const newEntries = entries.slice(1);
    setEntries(newEntries);
    setExpandedId(null);
    pushUpdate(newEntries, removed, "undo");
  }, [entries, pushUpdate]);

  const deleteEntry = useCallback((id) => {
    const removed = entries.find(e => e.id === id);
    const newEntries = entries.filter(e => e.id !== id);
    setEntries(newEntries);
    setExpandedId(null);
    pushUpdate(newEntries, removed, "delete");
  }, [entries, pushUpdate]);

  const updateEntry = useCallback((id, field, value) => {
    const newEntries = entries.map(e => e.id === id ? { ...e, [field]: value, ts: new Date().toISOString() } : e);
    setEntries(newEntries);
  }, [entries]);

  const saveAndCollapse = useCallback((id) => {
    setExpandedId(null);
    const entry = entries.find(e => e.id === id);
    if (entry) pushUpdate(entries, entry, "update");
  }, [entries, pushUpdate]);

  const toggleSoldItem = useCallback((entryId, catalogId) => {
    setEntries(prev => prev.map(e => {
      if (e.id !== entryId) return e;
      const ids = e.soldCatalogIds || [];
      const next = ids.includes(catalogId) ? ids.filter(x => x !== catalogId) : [...ids, catalogId];
      const sum = next.reduce((total, cid) => { const c = CATALOG.find(x => x.id === cid); return total + (c?.price || 0); }, 0);
      const shouldAutoFill = !e.amount || e.amount === "";
      return { ...e, soldCatalogIds: next, amount: shouldAutoFill ? String(sum) : e.amount, ts: new Date().toISOString() };
    }));
  }, []);

  // Derived: all sold catalog IDs across all entries
  const allSoldIds = new Set();
  entries.forEach(e => { if (e.engage === "Bought" && e.soldCatalogIds) e.soldCatalogIds.forEach(id => allSoldIds.add(id)); });

  const totalCount = entries.length;
  const boughtCount = entries.filter(e => e.engage === "Bought").length;
  const totalRevenue = entries.reduce((s, e) => { const a = parseFloat(e.amount); return s + (isNaN(a) ? 0 : a); }, 0);

  const exportData = () => { navigator.clipboard?.writeText?.(JSON.stringify(entries, null, 2)); alert("Copied"); };
  const clearData = () => { if (confirm("Clear all data?")) { setEntries([]); setNextId(1); setExpandedId(null); pushState(deployId, []); } };

  const filteredCatalog = CATALOG.filter(item => {
    const matchCat = catFilter === "All" || item.category === catFilter;
    const matchSearch = !search || item.name.toLowerCase().includes(search.toLowerCase()) || (item.price && item.price.toString().includes(search));
    return matchCat && matchSearch;
  });
  const grouped = {};
  filteredCatalog.forEach(item => { if (!grouped[item.category]) grouped[item.category] = []; grouped[item.category].push(item); });

  return (
    <div style={S.shell}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Instrument+Serif&family=DM+Mono:wght@400;500&display=swap');
        * { margin: 0; padding: 0; box-sizing: border-box; }
        body { background: #fff; }
        input::placeholder { color: #999; }
        input[type="number"]::-webkit-inner-spin-button { -webkit-appearance: none; }
        ::-webkit-scrollbar { width: 0; }
      `}</style>

      {/* CATALOG PICKER MODAL */}
      {showCatalogPicker !== null && (
        <div style={S.overlay} onClick={() => { setShowCatalogPicker(null); setPickerCat("All"); }}>
          <div style={S.pickerModal} onClick={e => e.stopPropagation()}>
            <div style={S.pickerHead}>
              <span style={S.pickerTitle}>What sold?</span>
              <button style={S.closeBtn} onClick={() => { setShowCatalogPicker(null); setPickerCat("All"); }}>✕</button>
            </div>
            <div style={S.rule} />
            <div style={S.catRow}>
              {CATEGORIES.map(c => (
                <button key={c} style={pickerCat === c ? S.catActive : S.catBtn} onClick={() => setPickerCat(c)}>{c}</button>
              ))}
            </div>
            <div style={S.rule} />
            <div style={S.pickerList}>
              {CATALOG.filter(c => pickerCat === "All" || c.category === pickerCat).map(item => {
                const entry = entries.find(e => e.id === showCatalogPicker);
                const isSelected = entry?.soldCatalogIds?.includes(item.id);
                const isSoldByOther = allSoldIds.has(item.id) && !isSelected;
                return (
                  <div key={item.id} style={{ ...S.pickerItem, textDecoration: isSoldByOther ? "line-through" : "none" }}
                    onClick={() => !isSoldByOther && toggleSoldItem(showCatalogPicker, item.id)}>
                    <div style={S.pickerCheck}>{isSelected ? "■" : "□"}</div>
                    <div style={S.pickerThumb}>
                      {IMAGES[item.id] ? <img src={IMAGES[item.id]} style={S.thumbImg} alt="" /> : <div style={S.thumbFallback}>?</div>}
                    </div>
                    <span style={S.pickerName}>{item.name}</span>
                    <span style={S.pickerPrice}>{item.price ? `$${item.price}` : "—"}</span>
                  </div>
                );
              })}
            </div>
            <button style={S.pickerDoneBtn} onClick={() => { setShowCatalogPicker(null); setPickerCat("All"); }}>Done</button>
          </div>
        </div>
      )}

      {/* SETTINGS */}
      {showSettings && (
        <div style={S.overlay} onClick={() => setShowSettings(false)}>
          <div style={S.modal} onClick={e => e.stopPropagation()}>
            <div style={S.modalHead}>
              <span style={S.modalTitle}>Settings</span>
              <button style={S.closeBtn} onClick={() => setShowSettings(false)}>✕</button>
            </div>
            <div style={S.rule} />
            <label style={S.label}>Google Sheets Deployment ID</label>
            <input style={S.modalInput} value={deployId} onChange={e => setDeployId(e.target.value.trim())} placeholder="AKfycbx..." />
            <p style={S.hint}>Apps Script → Deploy → Web app → copy the ID from the URL</p>
            {deployId && <p style={S.connectedText}>Connected · syncs every 60s</p>}
            <div style={S.rule} />
            <div style={S.modalBtnRow}>
              <button style={S.modalBtn} onClick={() => { doSync(); setShowSettings(false); }}>Sync now</button>
              <button style={S.modalBtn} onClick={exportData}>Export</button>
              <button style={S.modalBtn} onClick={clearData}>Clear</button>
            </div>
          </div>
        </div>
      )}

      {/* HEADER */}
      <div style={S.header}>
        <span style={S.logo}>NGD</span>
        <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
          {syncStatus && <span style={S.syncBadge}>{syncStatus}</span>}
          {boughtCount > 0 && <span style={S.headerStat}>{boughtCount} sold · ${totalRevenue}</span>}
          <button style={S.gearBtn} onClick={() => setShowSettings(true)}><GearIcon /></button>
        </div>
      </div>
      <div style={S.rule} />

      {tab === "count" ? (
        <div style={S.content}>
          <div style={S.counterArea}>
            <div style={S.bigNum}>{totalCount}</div>
            <div style={S.btnRow}>
              <button style={S.roundBtn} onClick={addEntry}><PersonIcon /></button>
            </div>
            <button style={S.undoBtn} onClick={undoEntry}>undo</button>
          </div>
          <div style={S.rule} />
          <div style={S.feed}>
            {entries.length === 0 && <div style={S.empty}>No one is here yet</div>}
            {entries.map(entry => (
              expandedId === entry.id ? (
                <ExpandedEntry key={entry.id} entry={entry} onUpdate={updateEntry}
                  onDone={() => saveAndCollapse(entry.id)} onDelete={() => deleteEntry(entry.id)} onPickCatalog={() => setShowCatalogPicker(entry.id)} />
              ) : (
                <CollapsedEntry key={entry.id} entry={entry} onTap={() => setExpandedId(entry.id)} allSoldIds={allSoldIds} />
              )
            ))}
          </div>
        </div>
      ) : (
        <div style={S.content}>
          <PriceCheck search={search} setSearch={setSearch} catFilter={catFilter} setCatFilter={setCatFilter} grouped={grouped} allSoldIds={allSoldIds} />
        </div>
      )}

      <div style={S.rule} />
      <div style={S.nav}>
        <button style={tab === "count" ? S.navActive : S.navBtn} onClick={() => setTab("count")}>Counter</button>
        <button style={tab === "price" ? S.navActive : S.navBtn} onClick={() => setTab("price")}>Price check</button>
      </div>
    </div>
  );
}

function CollapsedEntry({ entry, onTap }) {
  const isBought = entry.engage === "Bought";
  const hasSale = isBought && entry.amount;
  const dots = !entry.engage;
  const soldNames = (entry.soldCatalogIds || []).map(id => CATALOG.find(c => c.id === id)?.name).filter(Boolean);
  return (
    <div style={S.entryRow} onClick={onTap}>
      <div style={S.entryLeft}>
        <span style={S.entryNum}>#{entry.id}</span>
        <span style={S.entryTime}>{entry.time}</span>
      </div>
      <div style={S.entryRight}>
        {dots ? (
          <span style={S.dots}>· · · ·</span>
        ) : (
          <span style={{ ...S.tag, ...(isBought ? S.tagBought : {}) }}>{entry.engage}</span>
        )}
        {hasSale && <span style={S.saleAmt}>${entry.amount}</span>}
        {soldNames.length > 0 && <span style={S.itemsPrev}>{soldNames.join(", ").slice(0, 28)}{soldNames.join(", ").length > 28 ? "…" : ""}</span>}
        {entry.items && !soldNames.length && <span style={S.itemsPrev}>{entry.items.slice(0, 22)}{entry.items.length > 22 ? "…" : ""}</span>}
        {entry.note && !hasSale && <span style={S.notePrev}>{entry.note.slice(0, 20)}{entry.note.length > 20 ? "…" : ""}</span>}
      </div>
    </div>
  );
}

function ExpandedEntry({ entry, onUpdate, onDone, onDelete, onPickCatalog }) {
  const isBought = entry.engage === "Bought";
  const soldItems = (entry.soldCatalogIds || []).map(id => CATALOG.find(c => c.id === id)).filter(Boolean);
  return (
    <div style={S.entryExpanded}>
      <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 14 }}>
        <div>
          <span style={S.entryNum}>#{entry.id}</span>
          <span style={{ ...S.entryTime, marginLeft: 8 }}>{entry.time}</span>
        </div>
        <div style={{ display: "flex", gap: 8 }}>
          <button style={S.deleteBtn} onClick={onDelete}>delete</button>
          <button style={S.doneBtn} onClick={onDone}>done</button>
        </div>
      </div>
      <div style={S.pillRow}>
        {ENGAGEMENTS.map(eng => (
          <button key={eng} onClick={() => onUpdate(entry.id, "engage", eng)}
            style={entry.engage === eng ? S.pillActive : S.pill}>
            {eng}
          </button>
        ))}
      </div>
      {isBought && (
        <>
          <div style={S.saleBox}>
            <div style={S.saleRow}>
              <span style={S.dollar}>$</span>
              <input style={S.saleInput} type="number" inputMode="decimal" value={entry.amount}
                onChange={e => onUpdate(entry.id, "amount", e.target.value)} placeholder="0" autoFocus />
            </div>
            {soldItems.length === 0 ? (
              <button style={S.catalogPickBtn} onClick={onPickCatalog}>Select items from catalog</button>
            ) : (
              <div style={S.catalogPickRow}>
                <span style={S.catalogPickText}>{soldItems.length} item{soldItems.length > 1 ? "s" : ""} selected</span>
                <button style={S.editLink} onClick={onPickCatalog}>edit</button>
              </div>
            )}
            {soldItems.length > 0 && (
              <div style={S.soldList}>
                {soldItems.map(item => (
                  <div key={item.id} style={S.soldItem}>
                    <div style={S.soldThumb}>
                      {IMAGES[item.id] ? <img src={IMAGES[item.id]} style={S.thumbImg} alt="" /> : null}
                    </div>
                    <span style={S.soldName}>{item.name}</span>
                    <span style={S.soldPrice}>${item.price}</span>
                  </div>
                ))}
              </div>
            )}
            <input style={S.saleItemInput} value={entry.items}
              onChange={e => onUpdate(entry.id, "items", e.target.value)}
              placeholder='or type freehand — "bag + 2 charms"' />
          </div>
          <div style={S.payBox}>
            {["Venmo", "Zelle", "Cash"].map(m => (
              <button key={m} onClick={() => onUpdate(entry.id, "payment", m)}
                style={entry.payment === m ? S.payActive : S.payBtn}>{m}</button>
            ))}
          </div>
        </>
      )}
      <input style={S.noteInput} value={entry.note}
        onChange={e => onUpdate(entry.id, "note", e.target.value)} placeholder="note (optional)" />
    </div>
  );
}

function PriceCheck({ search, setSearch, catFilter, setCatFilter, grouped, allSoldIds }) {
  const ref = useRef(null);
  return (
    <div style={S.priceWrap}>
      <div style={S.searchWrap}>
        <input ref={ref} style={S.searchInput} value={search}
          onChange={e => setSearch(e.target.value)} placeholder="Search item or price…" />
        {search && <button style={S.clearBtn} onClick={() => { setSearch(""); ref.current?.focus(); }}>✕</button>}
      </div>
      <div style={S.rule} />
      <div style={S.catRow}>
        {CATEGORIES.map(c => (
          <button key={c} style={catFilter === c ? S.catActive : S.catBtn} onClick={() => setCatFilter(c)}>{c}</button>
        ))}
      </div>
      <div style={S.rule} />
      <div style={S.catalogScroll}>
        {Object.keys(grouped).length === 0 && <div style={S.empty}>No matches</div>}
        {Object.entries(grouped).map(([cat, items]) => (
          <div key={cat}>
            <div style={S.catHeader}>{cat}</div>
            <div style={S.rule} />
            {items.map(item => {
              const sold = allSoldIds.has(item.id);
              return (
                <div key={item.id} style={S.catItem}>
                  <div style={S.thumb}>
                    {IMAGES[item.id] ? <img src={IMAGES[item.id]} style={S.thumbImg} alt="" /> : <div style={S.thumbFallback}>?</div>}
                  </div>
                  <div style={S.catItemInfo}>
                    <span style={{ ...S.catItemName, textDecoration: sold ? "line-through" : "none" }}>
                      {item.name}
                      {item.qty > 1 && <span style={S.qtyTag}>×{item.qty}</span>}
                    </span>
                    {sold && <span style={S.soldTag}>SOLD</span>}
                    {item.addon && !sold && <span style={S.addonText}>add-on ${item.addon}</span>}
                  </div>
                  <span style={{ ...S.catItemPrice, textDecoration: sold ? "line-through" : "none" }}>
                    {item.price != null ? `$${item.price}` : "—"}
                  </span>
                </div>
              );
            })}
          </div>
        ))}
      </div>
    </div>
  );
}

